import{_ as e,o as i,c as p,ah as r}from"./chunks/framework.CkJUk41Q.js";const b=JSON.parse('{"title":"CI/CD","description":"","frontmatter":{"title":"CI/CD","order":40},"headers":[],"relativePath":"sde/workflow/devops/cicd/index.md","filePath":"sde/workflow/devops/cicd/index.md"}'),t={name:"sde/workflow/devops/cicd/index.md"};function n(h,a,l,d,o,c){return i(),p("div",null,[...a[0]||(a[0]=[r('<h1 id="持续集成与持续部署" tabindex="-1">持续集成与持续部署 <a class="header-anchor" href="#持续集成与持续部署" aria-label="Permalink to “持续集成与持续部署”">​</a></h1><p>持续集成与持续部署（CI/CD）是现代软件工程的核心实践，通过自动化构建、测试、部署流程，实现快速、可靠的软件交付。CI/CD 将繁琐的手工操作转化为可重复的自动化流程，让团队能够频繁发布代码变更，同时保持系统稳定。</p><h2 id="持续集成-ci" tabindex="-1">持续集成 CI <a class="header-anchor" href="#持续集成-ci" aria-label="Permalink to “持续集成 CI”">​</a></h2><p>持续集成要求开发人员频繁将代码集成到共享分支，每次集成都通过自动化构建和测试来验证。CI 的目标是尽早发现集成错误，减少问题修复成本。</p><h3 id="ci-核心实践" tabindex="-1">CI 核心实践 <a class="header-anchor" href="#ci-核心实践" aria-label="Permalink to “CI 核心实践”">​</a></h3><p>频繁提交：开发人员应该每天至少提交一次代码，小步快跑比大规模集成更安全。</p><p>自动化构建：每次代码提交触发自动构建，编译代码、打包依赖、生成可部署产物。</p><p>自动化测试：构建后运行自动化测试套件，包括单元测试、集成测试、静态分析。</p><p>快速反馈：构建和测试应该快速完成（通常在 10 分钟内），让开发者迅速获得反馈。</p><p>修复优先：构建失败时，团队优先修复问题，禁止在失败状态下继续开发。</p><h3 id="ci-流水线设计" tabindex="-1">CI 流水线设计 <a class="header-anchor" href="#ci-流水线设计" aria-label="Permalink to “CI 流水线设计”">​</a></h3><p>检出代码：从版本控制系统（如 Git）拉取最新代码。</p><p>安装依赖：根据包管理文件（package.json、pom.xml、go.mod）安装依赖。</p><p>代码检查：运行静态分析工具（ESLint、SonarQube）检查代码质量。</p><p>构建产物：编译代码、打包资源、生成 Docker 镜像。</p><p>运行测试：执行测试套件，收集测试覆盖率。</p><p>部署产物：将构建产物发布到制品库（如 Nexus、Docker Registry）。</p><p>通知结果：通过邮件、钉钉、Slack 通知构建结果。</p><h2 id="持续交付-cd" tabindex="-1">持续交付 CD <a class="header-anchor" href="#持续交付-cd" aria-label="Permalink to “持续交付 CD”">​</a></h2><p>持续交付在持续集成的基础上，确保代码可以随时部署到生产环境。CD 区分为持续交付（手动触发部署）和持续部署（自动部署）。</p><h3 id="cd-核心实践" tabindex="-1">CD 核心实践 <a class="header-anchor" href="#cd-核心实践" aria-label="Permalink to “CD 核心实践”">​</a></h3><p>环境一致性：开发、测试、生产环境尽可能一致，避免环境差异导致问题。</p><p>部署自动化：部署流程完全自动化，减少人为错误。</p><p>零停机部署：使用蓝绿部署、滚动更新实现零停机发布。</p><p>快速回滚：部署失败时能够快速回滚到上一个稳定版本。</p><p>特性开关：通过配置控制功能开关，实现功能灰度发布和快速关闭。</p><h3 id="部署策略" tabindex="-1">部署策略 <a class="header-anchor" href="#部署策略" aria-label="Permalink to “部署策略”">​</a></h3><p>蓝绿部署：维护两套环境（蓝和绿），部署新版本到空闲环境，测试通过后切换流量。优势：零停机、快速回滚。问题：资源成本翻倍。</p><p>滚动更新：逐个替换实例，逐渐将流量切换到新版本。优势：资源利用率高。问题：新旧版本共存，可能影响兼容性。</p><p>金丝雀发布：先发布到少量实例（金丝雀），观察指标正常后逐步扩大范围。优势：风险可控。问题：发布周期长。</p><p>灰度发布：根据用户特征（如地区、用户 ID）路由流量到不同版本，实现精细化发布。优势：精准控制。问题：实现复杂。</p><h2 id="ci-cd-工具链" tabindex="-1">CI/CD 工具链 <a class="header-anchor" href="#ci-cd-工具链" aria-label="Permalink to “CI/CD 工具链”">​</a></h2><h3 id="jenkins" tabindex="-1">Jenkins <a class="header-anchor" href="#jenkins" aria-label="Permalink to “Jenkins”">​</a></h3><p>Jenkins 是开源的自动化服务器，插件生态丰富，高度可定制。</p><p>Jenkins Pipeline：使用 Jenkinsfile 定义流水线，支持声明式和脚本式语法。</p><p>多分支流水线：为每个分支创建独立的流水线，支持 PR 自动触发。</p><p>插件生态：超过 1800 个插件，几乎集成所有开发工具。</p><h3 id="gitlab-ci-cd" tabindex="-1">GitLab CI/CD <a class="header-anchor" href="#gitlab-ci-cd" aria-label="Permalink to “GitLab CI/CD”">​</a></h3><p>GitLab CI/CD 内置于 GitLab，使用 <code>.gitlab-ci.yml</code> 定义流水线。</p><p>内置集成：无需额外安装，与 Git 仓库无缝集成。</p><p>Docker 支持：原生支持 Docker 构建和运行。</p><p>环境管理：支持定义多个环境，手动触发部署。</p><h3 id="github-actions" tabindex="-1">GitHub Actions <a class="header-anchor" href="#github-actions" aria-label="Permalink to “GitHub Actions”">​</a></h3><p>GitHub Actions 是 GitHub 的 CI/CD 平台，使用 YAML 文件定义工作流。</p><p>市场集成：丰富的第三方 Action，轻松集成各种服务。</p><p>矩阵构建：支持多操作系统、多版本并行测试。</p><p>自托管 Runner：支持私有服务器运行工作流。</p><h3 id="argocd" tabindex="-1">ArgoCD <a class="header-anchor" href="#argocd" aria-label="Permalink to “ArgoCD”">​</a></h3><p>ArgoCD 是 Kubernetes 的持续部署工具，采用 GitOps 模式。</p><p>声明式：Git 仓库是单一事实来源，自动同步状态。</p><p>可视化：提供应用拓扑图，清晰展示部署状态。</p><p>回滚：支持应用历史版本回滚。</p><h2 id="gitops-实践" tabindex="-1">GitOps 实践 <a class="header-anchor" href="#gitops-实践" aria-label="Permalink to “GitOps 实践”">​</a></h2><p>GitOps 是一种Ops 实践，使用 Git 作为单一事实来源，自动化同步基础设施和应用配置。</p><h3 id="gitops-核心原则" tabindex="-1">GitOps 核心原则 <a class="header-anchor" href="#gitops-核心原则" aria-label="Permalink to “GitOps 核心原则”">​</a></h3><p>声明式：系统状态声明式描述，存储在 Git 中。</p><p>版本化：所有变更通过 Git 提交，可审计、可回滚。</p><p>自动同步：自动化工具监控 Git 变更，同步到目标系统。</p><p>持续协调：工具持续监控实际状态与期望状态，自动纠正偏差。</p><h3 id="gitops-优势" tabindex="-1">GitOps 优势 <a class="header-anchor" href="#gitops-优势" aria-label="Permalink to “GitOps 优势”">​</a></h3><p>提高生产力：开发者无需直接操作集群，通过 PR 即可部署。</p><p>增强可靠性：Git 提供历史记录、回滚、权限控制。</p><p>快速恢复：配置错误时快速回滚到上一个稳定状态。</p><p>合规审计：Git 提交记录天然就是审计日志。</p><h2 id="质量门禁" tabindex="-1">质量门禁 <a class="header-anchor" href="#质量门禁" aria-label="Permalink to “质量门禁”">​</a></h2><p>质量门禁是在流水线中设置的质量检查点，只有通过检查才能进入下一阶段。</p><h3 id="门禁类型" tabindex="-1">门禁类型 <a class="header-anchor" href="#门禁类型" aria-label="Permalink to “门禁类型”">​</a></h3><p>代码覆盖率：要求测试覆盖率不低于阈值（如 80%）。</p><p>静态分析：运行静态分析工具，禁止严重问题通过。</p><p>安全扫描：扫描依赖漏洞，禁止高风险依赖。</p><p>性能测试：运行性能测试，要求响应时间、吞吐量达标。</p><p>人工审查：代码审查通过后才能合并到主分支。</p><h3 id="门禁配置" tabindex="-1">门禁配置 <a class="header-anchor" href="#门禁配置" aria-label="Permalink to “门禁配置”">​</a></h3><p>分级门禁：不同分支设置不同门禁级别，主分支要求最严格。</p><p>条件门禁：变更范围大时触发更多检查（如全量回归测试）。</p><p>豁免机制：紧急修复可豁免部分门禁，需要审批记录。</p><p>CI/CD 是现代软件工程的基础设施，理解 CI/CD 的原理和实践，有助于构建快速、可靠的交付体系。</p>',77)])])}const C=e(t,[["render",n]]);export{b as __pageData,C as default};
